import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.reap.global/api-reference/authentication";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";
const REAP_API_VERSION = "2025-02-14";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Reap API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:reap",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const reapFirewall = {",
    '  name: "reap",',
    '  description: "Reap API",',
    "  placeholders: {",
    `    REAP_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "${{ vars.REAP_API_BASE_URL }}",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.REAP_API_KEY }}",',
    `          "Reap-Version": "${REAP_API_VERSION}",`,
    "        },",
    "      },",
    "      permissions: [",
    "        {",
    '          name: "read",',
    '          description: "Read Reap resources",',
    '          rules: ["GET /{path+}"],',
    "        },",
    "        {",
    '          name: "write",',
    '          description: "Create, update, and delete Reap resources",',
    "          rules: [",
    '            "POST /{path+}",',
    '            "PUT /{path+}",',
    '            "PATCH /{path+}",',
    '            "DELETE /{path+}",',
    "          ],",
    "        },",
    "      ],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Reap firewall config...");
  const ts = generateTypeScript();
  writeOutput("reap", ts, import.meta.dirname);
}
